#include <iostream>
#include <vector>
#include <algorithm>

using namespace std;

struct Fenwick {
    int n;
    vector<int> tree;
    Fenwick(int n) : n(n), tree(n + 1, 0) {}
    void update(int i, int val) {
        for (; i <= n; i += i & -i) {
            tree[i] = max(tree[i], val);
        }
    }
    int query(int i) {
        int res = 0;
        for (; i > 0; i -= i & -i) {
            res = max(res, tree[i]);
        }
        return res;
    }
};

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);
    int n;
    long long d;
    if (!(cin >> n >> d)) return 0;
    vector<long long> a(n);
    vector<long long> u;
    for (int i = 0; i < n; ++i) {
        cin >> a[i];
        u.push_back(a[i]);
    }
    sort(u.begin(), u.end());
    u.erase(unique(u.begin(), u.end()), u.end());

    int m = u.size();
    Fenwick bit(m);
    int ans = 0;
    for (int i = 0; i < n; ++i) {
        long long limit = a[i] - d;
        auto it = upper_bound(u.begin(), u.end(), limit);
        int idx = distance(u.begin(), it);
        int dp_val = bit.query(idx) + 1;
        ans = max(ans, dp_val);

        int a_idx = lower_bound(u.begin(), u.end(), a[i]) - u.begin() + 1;
        bit.update(a_idx, dp_val);
    }
    cout << ans << "\n";
    return 0;
}
